import { useEffect, useState } from "react";
import axios from "axios";
import { useParams, useNavigate } from "react-router-dom";

export default function DriverRoute() {
  const { id } = useParams();

  const navigate = useNavigate();

  const [task, setTask] = useState(null);

  const getTask = async () => {
    try {
      const res = await axios.get(
        "http://localhost:3000/api/driver/today-task"
      );

      const found = res.data.requests.find(
        (item) => item._id === id
      );

      setTask(found);
    } catch (error) {
      console.log(error);
    }
  };

  useEffect(() => {
    getTask();
  }, []);

  const markArrived = async () => {
    try {
      const res = await axios.put(
        `http://localhost:3000/api/driver/arrived/${id}`
      );

      setTask(res.data.data);
    } catch (error) {
      console.log(error);
    }
  };

const markCompleted = async () => {
  try {
    const res = await axios.put(
      `http://localhost:3000/api/driver/completed/${id}`
    );

    setTask(res.data.data);

    setTimeout(() => {
      navigate("/driver-dashboard");
    }, 2000);

  } catch (error) {
    console.log(error);
  }
};

  if (!task) {
    return (
      <div className="min-h-screen flex justify-center items-center">
        Loading...
      </div>
    );
  }

return (
  <div className="min-h-screen bg-[#4CBB17]/10">

    {/* Top Route Bar */}
    <div className="bg-white shadow-md p-4">

      <h2 className="text-xl font-bold text-green-800">
        🚛 Route Navigation
      </h2>

      <div className="mt-2 bg-green-50 rounded-xl p-3 border">

        <p className="font-semibold text-gray-700">
          Start Point
        </p>

        <p className="text-sm text-gray-600">
          📍 MANIT Bhopal
        </p>

        <div className="my-2 text-center text-green-700 text-2xl">
          ↓
        </div>

        <p className="font-semibold text-gray-700">
          Destination
        </p>

        <p className="text-sm text-gray-600">
          📍 {task.location?.location}
        </p>

        <button
          onClick={() =>
            window.open(
              `https://www.google.com/maps/dir/23.2167,77.4061/${task.location?.latitude},${task.location?.longitude}`,
              "_blank"
            )
          }
          className="mt-4 w-full bg-blue-600 text-white py-3 rounded-xl font-semibold"
        >
          Open Route
        </button>

      </div>
    </div>

    {/* Action Section */}
    <div className="flex flex-col items-center mt-20">

      {task.arrivedAt && (
        <div className="bg-yellow-100 p-4 rounded-xl mb-4 w-96">
          <p className="font-bold">
            Arrived Time
          </p>

          <p>
            {new Date(task.arrivedAt).toLocaleString()}
          </p>
        </div>
      )}

      {task.completedAt && (
        <div className="bg-green-100 p-4 rounded-xl mb-4 w-96">
          <p className="font-bold">
            Completed Time
          </p>

          <p>
            {new Date(task.completedAt).toLocaleString()}
          </p>
        </div>
      )}

      {task.status === "Scheduled" && (
        <button
          onClick={markArrived}
          className="bg-yellow-500 text-white px-12 py-4 rounded-xl text-xl font-bold shadow-lg"
        >
          Arrived
        </button>
      )}

      {task.status === "Arrived" && (
        <button
          onClick={markCompleted}
          className="bg-green-600 text-white px-12 py-4 rounded-xl text-xl font-bold shadow-lg"
        >
          Completed
        </button>
      )}

    </div>

  </div>
);
}
